                    <FormattedInput label="Follow-up Fee" value={staffForm.consultationFeeFollowup} onChange={(val: string) => setStaffForm({...staffForm, consultationFeeFollowup: val})} prefix={<Hash size={14}/>} />
                    <FormattedInput label="Emergency Fee" value={staffForm.consultationFeeEmergency} onChange={(val: string) => setStaffForm({...staffForm, consultationFeeEmergency: val})} prefix={<Hash size={14}/>} />
                </div>
            )}
          </div>
          <div className="pt-4 border-t dark:border-slate-700">
            <h4 className="text-sm font-bold text-slate-500 mb-4 flex items-center gap-2"><Clock size={16}/> {t('staff_form_availability')}</h4>
            <div className="flex flex-wrap gap-2 mb-5">{DAYS_OF_WEEK.map((day) => (<button key={day} type="button" onClick={() => toggleDay(day)} className={`w-10 h-10 rounded-xl text-xs font-black transition-all ${ (staffForm.availableDays || []).includes(DAYS_OF_WEEK_EN[DAYS_OF_WEEK.indexOf(day)]) ? 'bg-primary-600 text-white shadow-lg shadow-primary-500/20' : 'bg-slate-100 dark:bg-slate-700 text-slate-400'}`}>{day}</button>))}</div>
            <div className="grid grid-cols-2 gap-4"><Input label={t('staff_form_start_time')} type="time" value={staffForm.availableTimeStart} onChange={e => setStaffForm({...staffForm, availableTimeStart: e.target.value})} /><Input label={t('staff_form_end_time')} type="time" value={staffForm.availableTimeEnd} onChange={e => setStaffForm({...staffForm, availableTimeEnd: e.target.value})} /></div>
          </div>
          <div className="flex justify-end pt-4 gap-3 border-t dark:border-slate-700 sticky bottom-[-24px] bg-white dark:bg-slate-800 py-3 z-10">
            <Button type="button" variant="secondary" onClick={() => setIsModalOpen(false)}>{t('cancel')}</Button>
            <Button type="submit" icon={Save}>{t('save')}</Button>
          </div>
        </form>
      </Modal>

      <Modal isOpen={isPayNowModalOpen} onClose={() => setIsPayNowModalOpen(false)} title="Payroll Disbursement">
        {selectedPayroll && (
          <form onSubmit={handlePayNowSubmit} className="space-y-6">
            <div className="p-6 bg-slate-50 dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800 text-center">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Disbursing Net Payout for {selectedPayroll.staffName}</p>
                <p className="text-4xl font-black text-primary-600 font-mono tracking-tighter">${selectedPayroll.netSalary.toLocaleString()}</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <Select label="Payment Method" value={payNowForm.method} onChange={e => setPayNowForm({...payNowForm, method: e.target.value})} required>
                   {paymentMethods.filter(pm => pm.isActive).map(pm => <option key={pm.id} value={pm.name_en}>{pm.name_en}</option>)}
                </Select>
                <Input label="Transaction Ref / Chq #" placeholder="Ref: 0012345" value={payNowForm.reference} onChange={e => setPayNowForm({...payNowForm, reference: e.target.value})} />
            </div>
            <Textarea label="Internal Disbursement Notes" placeholder="Paid as part of monthly salary run..." value={payNowForm.notes} onChange={e => setPayNowForm({...payNowForm, notes: e.target.value})} />
            <div className="pt-4 flex justify-end gap-3 border-t dark:border-slate-700">
               <Button type="button" variant="secondary" onClick={() => setIsPayNowModalOpen(false)}>{t('cancel')}</Button>
               <Button type="submit" icon={CheckCircle}>Confirm Payment</Button>
            </div>
          </form>
        )}
      </Modal>

      <Modal isOpen={isPayrollDetailModalOpen} onClose={() => setIsPayrollDetailModalOpen(false)} title={`Salary Breakdown: ${selectedPayroll?.staffName}`}>
         {selectedPayroll && (
            <div className="space-y-6">
                <div className="p-6 bg-slate-50 dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800 text-center">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Net Payout ({selectedPayroll.month})</p>
                    <p className="text-4xl font-black text-primary-600 font-mono tracking-tighter">${selectedPayroll.netSalary.toLocaleString()}</p>
                    <div className="mt-4 flex justify-center"><Badge color={selectedPayroll.status === 'paid' ? 'green' : 'yellow'}>{selectedPayroll.status.toUpperCase()}</Badge></div>
                </div>

                <div className="space-y-3">
                    <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest px-1">Calculation Summary</h4>
                    <div className="bg-white dark:bg-slate-800 border rounded-2xl overflow-hidden shadow-sm">
                        <div className="p-4 flex justify-between items-center border-b dark:border-slate-700">
                           <span className="text-sm font-medium text-slate-600 dark:text-slate-400 flex items-center gap-2"><Briefcase size={14}/> Monthly Base Salary</span>
                           <span className="font-mono font-bold text-slate-900 dark:text-white">${selectedPayroll.baseSalary.toLocaleString()}</span>
                        </div>
                        <div className="p-4 flex justify-between items-center border-b dark:border-slate-700 bg-emerald-50/30 dark:bg-emerald-900/10">
                           <span className="text-sm font-medium text-emerald-700 dark:text-emerald-400 flex items-center gap-2"><Plus size={14}/> Bonuses & Additions</span>
                           <span className="font-mono font-bold text-emerald-600">+${selectedPayroll.totalBonuses.toLocaleString()}</span>
