                        <div className="p-4 flex justify-between items-center bg-rose-50/30 dark:bg-rose-900/10">
                           <span className="text-sm font-medium text-rose-700 dark:text-rose-400 flex items-center gap-2"><Hash size={14}/> Fines & Deductions</span>
