                                    {selected && (
                                      <div className={`absolute top-2 ${isRtl ? 'left-2' : 'right-2'} text-primary-600 animate-in zoom-in-50 duration-200`}>
                                        <CheckCircle size={16} />
                                      </div>
                                    )}
                                </div>
                            );
