const getStatusColor = (status: string) => {
  const s = (status || '').toLowerCase();
  if (s.includes('paid') || s.includes('complete') || s.includes('active') || s.includes('regis')) return 'green';
  if (s.includes('pending') || s.includes('waiting') || s.includes('reserved') || s.includes('confirmed')) return 'yellow';
  if (s.includes('cancelled') || s.includes('refunded') || s.includes('overdue')) return 'red';
  return 'blue';
};

const translateStatus = (status: string, t: any) => {
    const s = status.toLowerCase();
    if (s === 'paid') return t('billing_status_paid');
    if (s === 'pending') return t('billing_status_pending');
    if (s === 'partial') return t('billing_status_partial');
    if (s === 'overdue') return t('billing_status_overdue');
    if (s === 'refunded') return t('billing_status_refunded');
    return status;
};

const HashIcon = ({ size, className }: any) => <span className={className}>#</span>;

import axios from 'axios';

// Helper to determine the correct base URL based on the current environment
const getBaseUrl = () => {
  const { hostname } = window.location;

  // 1. Local Development (uses Vite proxy in vite.config.js)
  // 2. Production Deployment (served by Express on same domain)
  if (hostname === 'localhost' || hostname === '127.0.0.1' || hostname.includes('railway.app')) {
    return '/api';
  }

  // 3. External Environments (e.g. Google AI Studio, StackBlitz, Local Network)
  // Connect directly to the deployed Railway backend
  return 'https://allcare.up.railway.app/api';
};

const client = axios.create({
  baseURL: getBaseUrl(),
  headers: { 'Content-Type': 'application/json' },
  timeout: 30000,
});

client.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

// Added a simple retry mechanism for 429 errors to improve robustness
client.interceptors.response.use(
  (response) => response.data,
  async (error) => {
    const { config, response } = error;

    // Auto-retry once on 429 with a small delay
    if (response?.status === 429 && !config._retry) {
      config._retry = true;
      console.warn('Rate limit hit, retrying in 1s...');
      await new Promise(resolve => setTimeout(resolve, 1000));
      return client(config);
    }

    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      window.location.href = '/'; 
    }
    if (!error.response && error.code !== 'ERR_CANCELED') {
      console.error('Network Error: Backend unreachable.');
    }
    return Promise.reject(error);
  }
);

// Helpers to cast response to any, ensuring TS treats return values as data objects (unwrapped by interceptor)
const get = (url: string) => client.get(url) as Promise<any>;
const post = (url: string, data?: any, config?: any) => client.post(url, data, config) as Promise<any>;
const put = (url: string, data?: any) => client.put(url, data) as Promise<any>;
const del = (url: string) => client.delete(url) as Promise<any>;

export const api = {
  login: (username, password) => post('/auth/login', { username, password }),
  me: () => get('/auth/me'),
  updateProfile: (data) => put('/auth/profile', data),
  changePassword: (data) => put('/auth/password', data),
  checkSystemHealth: () => get('/config/health'),

  getPatients: () => get('/patients'),
  getPatient: (id) => get(`/patients/${id}`),
  addPatient: (data) => post('/patients', data),
  updatePatient: (id, data) => put(`/patients/${id}`, data),

  getStaff: () => get('/hr'),
  addStaff: (data) => post('/hr', data),
  updateStaff: (id, data) => put(`/hr/${id}`, data),
